const ALL_PEOPLE = [...PEOPLE, ...EXTRA_PEOPLE]

function getInitials(n) { return n.split(' ').map(w=>w[0]).join('').slice(0,2) }
function stageConf(key) { return STAGES.find(s=>s.key===key)||STAGES[0] }
function fmt(n) { return new Intl.NumberFormat('en-US',{style:'currency',currency:'USD'}).format(n) }
function tagConf(id) { return ALL_TAGS.find(t=>t.id===id)||ALL_TAGS[0] }
// Expand short date seeds into readable full format
const MONTH_MAP = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11}
function expandTs(ts) {
  if (!ts) return '—'
  if (ts.includes(',')) return ts
  const match = ts.match(/^([A-Za-z]+)\s+(\d+)$/)
  if (match) return `${match[1]} ${match[2]}, 2026`
  return ts
}
// Format created date with a plausible time based on seed id
function fmtCreated(ts, id='') {
  if (!ts) return '—'
  // If already has time, return as-is
  if (ts.includes(':')) return ts
  const base = expandTs(ts)
  // Generate a deterministic but plausible time from the id string
  const hash = id.split('').reduce((h,c)=>h+c.charCodeAt(0),0)
  const hour = 8 + (hash % 10)
  const min  = (hash * 7) % 60
  const ampm = hour < 12 ? 'AM' : 'PM'
  const h12  = hour > 12 ? hour - 12 : hour
  return `${base} · ${h12}:${min.toString().padStart(2,'0')} ${ampm}`
}

function Avatar({ name, size=32, muted=false }) {
  return <div style={{ width:size, height:size, borderRadius:size*0.28, background:muted?'rgba(0,0,0,0.12)':'linear-gradient(135deg,#a8c9c4,#7ab5af)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:size*0.33, fontWeight:700, color:'white', flexShrink:0, fontFamily:'Georgia,serif' }}>{getInitials(name)}</div>
}

const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'16px', fontFamily:'inherit', color:'#1a2e2b', background:'white', outline:'none', boxSizing:'border-box' }
const handle = <div style={{ width:'36px', height:'4px', background:'rgba(0,0,0,0.12)', borderRadius:'2px', margin:'0 auto 1rem' }} />

// ─── Sad Animation ────────────────────────────────────────────────────────────
const SAD_FACES = ['😢','😔','💔','😞','🥺','😿']

const MOTIVATIONAL = [
  "Not every lead is the right fit - the right ones are coming 🐝",
  "Every no gets you closer to the next yes ✨",
  "Keep going - your next great client is out there 💪",
  "Shake it off. The hive keeps buzzing 🍯",
  "Quality over quantity - always 🌟",
  "On to the next one. You've got this 🚀",
  "Every closed door opens a better window 🪟",
  "The best organizers know when to let go 🧹",
]

function SadAnimation() {
  const message = MOTIVATIONAL[Math.floor(Math.random() * MOTIVATIONAL.length)]
  const [particles] = useState(() =>
    Array.from({ length: 24 }, (_, i) => ({
      id: i,
      emoji: SAD_FACES[Math.floor(Math.random() * SAD_FACES.length)],
      left: Math.random() * 100,
      delay: Math.random() * 2.5,
      size: 20 + Math.floor(Math.random() * 24),
      duration: 2.0 + Math.random() * 1.5,
    }))
  )

  return (
    <div style={{ position:'fixed', inset:0, zIndex:20000, pointerEvents:'none', overflow:'hidden' }}>
      <style>{`
        @keyframes sadFall {
          0%   { transform: translateY(-60px) rotate(0deg); opacity:1; }
          80%  { opacity:1; }
          100% { transform: translateY(110vh) rotate(20deg); opacity:0; }
        }
        @keyframes fadeInUp {
          0%   { opacity:0; transform:translateY(16px); }
          100% { opacity:1; transform:translateY(0); }
        }
        .sad-particle {
          position: absolute;
          top: -60px;
          animation: sadFall var(--dur) ease-in var(--delay) forwards;
        }
        .sad-card {
          animation: fadeInUp 0.4s ease forwards;
        }
      `}</style>
      {particles.map(p => (
        <div key={p.id} className="sad-particle" style={{ left:`${p.left}%`, fontSize:`${p.size}px`, '--dur':`${p.duration}s`, '--delay':`${p.delay}s` }}>
          {p.emoji}
        </div>
      ))}
      <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center' }}>
        <div className="sad-card" style={{ background:'rgba(26,46,43,0.92)', borderRadius:'20px', padding:'28px 32px', textAlign:'center', maxWidth:'280px', boxShadow:'0 8px 40px rgba(0,0,0,0.3)' }}>
          <p style={{ fontSize:'40px', marginBottom:'10px' }}>😢</p>
          <p style={{ fontSize:'15px', color:'white', fontWeight:600, marginBottom:'8px' }}>Record closed</p>
          <p style={{ fontSize:'13px', color:'rgba(168,201,196,0.9)', lineHeight:1.5, marginBottom:'14px' }}>{message}</p>
          <div style={{ height:'3px', background:'rgba(168,201,196,0.2)', borderRadius:'2px', overflow:'hidden' }}>
            <div style={{ height:'100%', background:'#a8c9c4', borderRadius:'2px', animation:'progress 3.5s linear forwards' }} />
          </div>
          <style>{`@keyframes progress { from { width:0% } to { width:100% } }`}</style>
        </div>
      </div>
    </div>
  )
}

// ─── Popup wrapper ────────────────────────────────────────────────────────────
function Popup({ title, onClose, children, maxW='480px' }) {
  return (
    <div style={{ position:'fixed', top:0, left:0, right:0, bottom:0, zIndex:10002, display:'flex', alignItems:'center', justifyContent:'center', padding:'12px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(26,46,43,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', width:'100%', maxWidth:maxW, borderRadius:'16px', padding:'1.25rem', zIndex:1, maxHeight:'88vh', overflowY:'auto', boxShadow:'0 8px 40px rgba(26,46,43,0.2)', boxSizing:'border-box', overflowX:'hidden' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'1.25rem' }}>
          <h3 style={{ fontSize:'16px', fontFamily:'Georgia,serif', color:'#1a2e2b' }}>{title}</h3>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'20px', color:'#8a9e9a', cursor:'pointer' }}>×</button>
        </div>
        {children}
      </div>
    </div>
  )
}

// ─── Won Animation ────────────────────────────────────────────────────────────
const WON_EMOJIS = ['🎉','🏆','🐝','💰','⭐','🎊','✨','🍯','💪','🎯']
const WON_MESSAGES = [
  "Boom! Another one bites the dust 🏆",
  "That's what we're talking about! Money in the hive 🍯",
  "Closed and delivered. You're on fire 🔥",
  "Another happy client. The hive grows stronger 🐝",
  "Cha-ching! Keep that momentum going 💰",
  "Done and dusted. On to the next one ✨",
  "You crushed it. Client happy, hive happy 🎉",
  "Another win for the books. Let's go! 🎯",
]

function WonAnimation() {
  const message = WON_MESSAGES[Math.floor(Math.random() * WON_MESSAGES.length)]
  const [particles] = useState(() =>
    Array.from({ length: 24 }, (_, i) => ({
      id: i,
      emoji: WON_EMOJIS[Math.floor(Math.random() * WON_EMOJIS.length)],
      left: Math.random() * 100,
      delay: Math.random() * 2.5,
      size: 20 + Math.floor(Math.random() * 24),
      duration: 2.0 + Math.random() * 1.5,
    }))
  )

  return (
    <div style={{ position:'fixed', inset:0, zIndex:20000, pointerEvents:'none', overflow:'hidden' }}>
      <style>{`
        @keyframes wonFall {
          0%   { transform: translateY(-60px) rotate(0deg); opacity:1; }
          80%  { opacity:1; }
          100% { transform: translateY(110vh) rotate(20deg); opacity:0; }
        }
        @keyframes wonSlideUp {
          0%   { opacity:0; transform:translateY(16px); }
          100% { opacity:1; transform:translateY(0); }
        }
        .won-particle {
          position: absolute;
          top: -60px;
          animation: wonFall var(--dur) ease-in var(--delay) forwards;
        }
        .won-card { animation: wonSlideUp 0.4s ease forwards; }
      `}</style>
      {particles.map(p => (
        <div key={p.id} className="won-particle" style={{ left:`${p.left}%`, fontSize:`${p.size}px`, '--dur':`${p.duration}s`, '--delay':`${p.delay}s` }}>
          {p.emoji}
        </div>
      ))}
      <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center' }}>
        <div className="won-card" style={{ background:'linear-gradient(135deg,#d4a046,#e8c060)', borderRadius:'20px', padding:'28px 32px', textAlign:'center', maxWidth:'280px', boxShadow:'0 8px 40px rgba(212,160,70,0.5)' }}>
          <p style={{ fontSize:'40px', marginBottom:'10px' }}>🏆</p>
          <p style={{ fontSize:'15px', color:'#1a2e2b', fontWeight:600, marginBottom:'8px' }}>Closed Won!</p>
          <p style={{ fontSize:'13px', color:'rgba(26,46,43,0.75)', lineHeight:1.5, marginBottom:'14px' }}>{message}</p>
          <div style={{ height:'3px', background:'rgba(26,46,43,0.15)', borderRadius:'2px', overflow:'hidden' }}>
            <div style={{ height:'100%', background:'#1a2e2b', borderRadius:'2px', animation:'wonProgress 4s linear forwards' }} />
          </div>
          <style>{`@keyframes wonProgress { from { width:0% } to { width:100% } }`}</style>
        </div>
      </div>
    </div>
  )
}


function ReachOutPopup({ person, onDone, onClose }) {
  const [method, setMethod] = useState(null)
  const [note, setNote] = useState('')
  const methods = [{key:'call',icon:'📞',label:'Phone Call'},{key:'sms',icon:'💬',label:'Text'},{key:'email',icon:'📧',label:'Email'}]

  function confirm() {
    if (!method) return
    const labels = {call:'Phone Call',sms:'Text',email:'Email'}
    const newEntry = { id:`o${Date.now()}`, type:'manual', method, label:`Reached out via ${labels[method]}${note?' - '+note:''}`, ts:'Just now', status:'done', user:'You' }
    const isFirst = !person.reachOutMethod
    onDone({
      reachOutMethod: person.reachOutMethod||method,
      stage: isFirst?'Attempting':person.stage,
      outreachTimeline: [...person.outreachTimeline, newEntry],
    })
  }

  return (
    <Popup title="Log Reach Out" onClose={onClose}>
      <p style={{ fontSize:'13px', color:'#8a9e9a', marginBottom:'1rem' }}>You can log multiple reach-outs. Each will appear in the outreach timeline.</p>
      <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'8px', marginBottom:'1rem' }}>
        {methods.map(m=>(
          <button key={m.key} onClick={()=>setMethod(m.key)} style={{ padding:'14px 8px', borderRadius:'12px', cursor:'pointer', border:'2px solid', borderColor:method===m.key?'#a8c9c4':'rgba(0,0,0,0.08)', background:method===m.key?'rgba(168,201,196,0.12)':'white', display:'flex', flexDirection:'column', alignItems:'center', gap:'6px', fontFamily:'inherit' }}>
            <span style={{ fontSize:'24px' }}>{m.icon}</span>
            <span style={{ fontSize:'12px', fontWeight:600, color:'#1a2e2b' }}>{m.label}</span>
          </button>
        ))}
      </div>
      <input style={{...inp, marginBottom:'1.25rem'}} placeholder="Notes - left voicemail, no answer, etc." value={note} onChange={e=>setNote(e.target.value)} />
      <div style={{ display:'flex', gap:'10px' }}>
        <button onClick={onClose} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
        <button onClick={confirm} disabled={!method} style={{ flex:2, padding:'12px', background:method?'#f97316':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:method?'white':'#9ca3af', cursor:method?'pointer':'not-allowed' }}>Log Reach Out</button>
      </div>
    </Popup>
  )
}

// ─── Tag Manager Popup ────────────────────────────────────────────────────────
function TagPopup({ person, onSave, onClose }) {
  const [selected, setSelected] = useState([...person.tags])

  function toggle(id) {
    setSelected(prev => prev.includes(id) ? prev.filter(x=>x!==id) : [...prev, id])
  }

  return (
    <Popup title="Tags" onClose={onClose}>
      <p style={{ fontSize:'13px', color:'#8a9e9a', marginBottom:'1rem' }}>Tag this lead to help with filtering and follow-up.</p>
      <div style={{ display:'grid', gap:'8px', marginBottom:'1.25rem' }}>
        {ALL_TAGS.map(tag=>{
          const active = selected.includes(tag.id)
          return (
            <button key={tag.id} onClick={()=>toggle(tag.id)} style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'11px 14px', background:active?tag.bg:'white', border:`1.5px solid ${active?tag.color+'50':'rgba(0,0,0,0.08)'}`, borderRadius:'10px', cursor:'pointer', fontFamily:'inherit' }}>
              <span style={{ fontSize:'14px', fontWeight:500, color:active?tag.color:'#1a2e2b' }}>{tag.label}</span>
              <div style={{ width:'20px', height:'20px', borderRadius:'6px', border:`2px solid ${active?tag.color:'rgba(0,0,0,0.15)'}`, background:active?tag.color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}>
                {active&&<span style={{ fontSize:'11px', color:'white', fontWeight:700 }}>✓</span>}
              </div>
            </button>
          )
        })}
      </div>
      <div style={{ display:'flex', gap:'10px' }}>
        <button onClick={onClose} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
        <button onClick={()=>onSave(selected)} style={{ flex:2, padding:'12px', background:'#1a2e2b', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:'white', cursor:'pointer' }}>Save Tags</button>
      </div>
    </Popup>
  )
}

// ─── Close Popup ──────────────────────────────────────────────────────────────
// Default closed lost reasons - editable in Admin → Configure
const DEFAULT_CLOSE_REASONS = [
  'Price too high',
  'Hired competitor',
  'No longer moving',
  'Went with friend/family',
  'Unresponsive - timed out',
  'Budget on hold',
  'Already organized',
  'Changed mind',
  'Out of service area',
  'Duplicate record',
  'Spam / Bot',
  'Other',
]
// Shared mutable list - ConfigureTab writes here, ClosePopup reads here
let _closeLostReasons = DEFAULT_CLOSE_REASONS.slice()
function getCloseLostReasons() { return Array.isArray(_closeLostReasons) ? _closeLostReasons : DEFAULT_CLOSE_REASONS }
function setCloseLostReasons(list) { if(Array.isArray(list)) _closeLostReasons = list }

// Admin-managed specialties
let _specialties = null
function getSpecialties() { return _specialties || SPECIALTIES }
function setAdminSpecialties(list) { _specialties = list }

// Admin-managed partner tiers
let _partnerTiers = null
function getPartnerTiers() { return _partnerTiers || PARTNER_TIERS }
function setAdminPartnerTiers(list) { _partnerTiers = list }

// Location default drip path - set by Settings Paths tab
let _defaultPathId = 'general-a'
let _defaultMovePathId = 'move-a'
function getDefaultPathId() { return _defaultPathId }
function getDefaultMovePathId() { return _defaultMovePathId }
function setDefaultPathId(id) { if(id) _defaultPathId = id }
function setDefaultMovePathId(id) { if(id) _defaultMovePathId = id }

// Project type → drip category map - admin-editable via Configure tab
let _projectTypeCategories = null // lazily initialized on first access
function getProjectTypeCategories() {
  if (!_projectTypeCategories) {
    _projectTypeCategories = Object.fromEntries(
      PROJECT_TYPES.map(t => [t, ['Move-In Organization','Move-Out Organization'].includes(t) ? 'move' : 'general'])
    )
  }
  return _projectTypeCategories
}
function setProjectTypeCategories(map) { _projectTypeCategories = map }
function getProjectCategory(projectType) {
  return (getProjectTypeCategories()[projectType] || 'general')
}
function getDefaultPathForProject(projectType) {
  const cat = getProjectCategory(projectType)
  const id = cat==='move' ? getDefaultMovePathId() : getDefaultPathId()
  return DRIP_PATHS_CONFIG.find(p=>p.id===id) || DRIP_PATHS_CONFIG.find(p=>p.projectType===cat) || DRIP_PATHS_CONFIG[0]
}

function ProcessLeadSheet({ person, onSave, onClose }) {
  const isWakeUp    = !!person.snoozeUntil
  const isCapture   = !!person.quickCapture
  const [step, setStep] = useState(0)
  const [project, setProject] = useState(person.project||'')
  const [source, setSource]   = useState(person.source||'')
  const [pathId, setPathId]   = useState(null)
  const [note, setNote]       = useState('')
  const [showMorePaths, setShowMorePaths] = useState(false)

  const steps = [
    ...(isWakeUp ? [{ key:'context' }] : []),
    ...(!person.project ? [{ key:'project' }] : []),
    { key:'path' },
    { key:'confirm' },
  ]
  const cur = steps[step]

  function next() { if (step < steps.length-1) setStep(s=>s+1) }
  function back() { if (step > 0) setStep(s=>s-1) }

  function finish() {
    const cat      = project ? getProjectCategory(project) : 'general'
    const defId    = cat==='move' ? getDefaultMovePathId() : getDefaultPathId()
    const chosen   = pathId || defId
    const finalPath = chosen==='none' ? null : chosen
    onSave({
      ...person,
      project:     project || person.project,
      source:      source  || person.source,
      path:        finalPath,
      stage:       'Attempting',
      snoozeUntil: null,
      snoozeNote:  null,
      quickCapture: false,
      reachOutMethod: null,
      activity: [...(person.activity||[]), {
        type:'process', label: isWakeUp
          ? `Lead re-activated${note?' · '+note:''}`
          : `Quick capture processed → drip assigned`,
        ts:'Just now', user:'You'
      }]
    })
    onClose()
  }

  const defCat    = project ? getProjectCategory(project) : 'general'
  const catPaths  = DRIP_PATHS_CONFIG.filter(p=>p.projectType===defCat)
  const defPathId = defCat==='move' ? getDefaultMovePathId() : getDefaultPathId()
  const defPath   = catPaths.find(p=>p.id===(pathId||defPathId)) || catPaths[0]
  const others    = catPaths.filter(p=>p.id!==defPath?.id)

  return (
    <div style={{ position:'fixed', inset:0, zIndex:10003, display:'flex', alignItems:'center', justifyContent:'center', padding:'12px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(26,46,43,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', width:'100%', maxWidth:'460px', borderRadius:'20px', padding:'1.5rem', zIndex:1, boxShadow:'0 20px 60px rgba(26,46,43,0.25)', maxHeight:'88vh', overflowY:'auto' }}>

        {/* Progress dots */}
        <div style={{ display:'flex', justifyContent:'center', gap:'6px', marginBottom:'16px' }}>
          {steps.map((_,i)=>(
            <div key={i} style={{ width:'8px', height:'8px', borderRadius:'50%', background:i===step?'#1a2e2b':i<step?'#a8c9c4':'rgba(0,0,0,0.12)', transition:'background 0.2s' }} />
          ))}
        </div>

        {/* CONTEXT step - wake-up only */}
        {cur?.key==='context'&&(
          <div style={{ display:'grid', gap:'12px' }}>
            <div>
              <h3 style={{ fontSize:'18px', fontFamily:'Georgia,serif', color:'#1a2e2b', marginBottom:'4px' }}>⏰ {person.name} is back</h3>
              <p style={{ fontSize:'12px', color:'#8a9e9a' }}>Snoozed: {person.snoozeNote||'No note'}</p>
            </div>
            <textarea value={note} onChange={e=>setNote(e.target.value)} placeholder="Why are they ready now? Any context before re-engaging…" rows={3}
              style={{ width:'100%', padding:'9px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'9px', fontSize:'13px', fontFamily:'inherit', outline:'none', resize:'none', boxSizing:'border-box' }} />
            <div style={{ display:'flex', gap:'8px' }}>
              <button onClick={onClose} style={{ flex:1, padding:'11px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', color:'#8a9e9a', cursor:'pointer' }}>Not yet</button>
              <button onClick={next} style={{ flex:2, padding:'11px', background:'#1a2e2b', border:'none', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer' }}>Re-engage → </button>
            </div>
          </div>
        )}

        {/* PROJECT step */}
        {cur?.key==='project'&&(
          <div style={{ display:'grid', gap:'12px' }}>
            <h3 style={{ fontSize:'18px', fontFamily:'Georgia,serif', color:'#1a2e2b' }}>What's the project?</h3>
            <select value={project} onChange={e=>setProject(e.target.value)} autoFocus
              style={{ width:'100%', padding:'11px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'9px', fontSize:'14px', fontFamily:'inherit', color:project?'#1a2e2b':'#8a9e9a', outline:'none', appearance:'none' }}>
              <option value=''>Select project type…</option>
              {PROJECT_TYPES.map(s=><option key={s}>{s}</option>)}
            </select>
            <div style={{ display:'flex', gap:'8px' }}>
              <button onClick={back} style={{ flex:1, padding:'11px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', color:'#8a9e9a', cursor:'pointer' }}>← Back</button>
              <button onClick={next} disabled={!project} style={{ flex:2, padding:'11px', background:project?'#1a2e2b':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', fontWeight:600, color:project?'white':'#9ca3af', cursor:project?'pointer':'not-allowed' }}>Next →</button>
            </div>
          </div>
        )}

        {/* PATH step */}
        {cur?.key==='path'&&(
          <div style={{ display:'grid', gap:'10px' }}>
            <div>
              <h3 style={{ fontSize:'18px', fontFamily:'Georgia,serif', color:'#1a2e2b', marginBottom:'2px' }}>Which New Lead Drip?</h3>
              <p style={{ fontSize:'12px', color:'#8a9e9a' }}>{project?`${project} → ${defCat==='move'?'Move':'General'} paths`:'General paths'}</p>
            </div>
            {/* No drip option */}
            <div onClick={()=>setPathId('none')} style={{ display:'flex', alignItems:'center', gap:'10px', padding:'11px 12px', background:pathId==='none'?'rgba(239,68,68,0.05)':'white', border:`1.5px solid ${pathId==='none'?'rgba(239,68,68,0.3)':'rgba(0,0,0,0.08)'}`, borderRadius:'9px', cursor:'pointer' }}>
              <span style={{ fontSize:'18px' }}>🚫</span>
              <div style={{ flex:1 }}>
                <p style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b' }}>No New Lead Drip</p>
                <p style={{ fontSize:'11px', color:'#8a9e9a' }}>Create without automated outreach</p>
              </div>
              {pathId==='none'&&<span style={{ color:'#ef4444' }}>✓</span>}
            </div>
            {defPath&&(
              <div onClick={()=>setPathId(defPath.id)} style={{ display:'flex', alignItems:'center', gap:'10px', padding:'12px', background:(pathId||defPathId)===defPath.id?'rgba(168,201,196,0.12)':'white', border:`1.5px solid ${(pathId||defPathId)===defPath.id?'#a8c9c4':'rgba(0,0,0,0.08)'}`, borderRadius:'9px', cursor:'pointer' }}>
                <span style={{ fontSize:'18px' }}>{defPath.icon}</span>
                <div style={{ flex:1 }}>
                  <div style={{ display:'flex', gap:'6px', marginBottom:'2px' }}>
                    <p style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b' }}>{defPath.name}</p>
                    <span style={{ fontSize:'10px', color:'#a8c9c4', background:'rgba(168,201,196,0.12)', padding:'1px 7px', borderRadius:'20px' }}>Default</span>
                  </div>
                  <p style={{ fontSize:'11px', color:'#8a9e9a' }}>{defPath.desc}</p>
                </div>
                {(pathId||defPathId)===defPath.id&&<span style={{ color:'#a8c9c4' }}>✓</span>}
              </div>
            )}
            <button onClick={()=>setShowMorePaths(s=>!s)} style={{ padding:'8px', background:'none', border:'1px dashed rgba(0,0,0,0.1)', borderRadius:'9px', cursor:'pointer', fontFamily:'inherit', fontSize:'12px', color:'#8a9e9a' }}>
              {showMorePaths?'▲ Hide':'▼ Other paths'}
            </button>
            {showMorePaths&&others.map(p=>(
              <div key={p.id} onClick={()=>setPathId(p.id)} style={{ display:'flex', alignItems:'center', gap:'10px', padding:'10px 12px', background:pathId===p.id?'rgba(168,201,196,0.12)':'white', border:`1.5px solid ${pathId===p.id?'#a8c9c4':'rgba(0,0,0,0.08)'}`, borderRadius:'9px', cursor:'pointer' }}>
                <span style={{ fontSize:'18px' }}>{p.icon}</span>
                <div style={{ flex:1 }}>
                  <p style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b' }}>{p.name}</p>
                  <p style={{ fontSize:'11px', color:'#8a9e9a' }}>{p.desc}</p>
                </div>
                {pathId===p.id&&<span style={{ color:'#a8c9c4' }}>✓</span>}
              </div>
            ))}
            <div style={{ display:'flex', gap:'8px' }}>
              <button onClick={back} style={{ flex:1, padding:'11px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', color:'#8a9e9a', cursor:'pointer' }}>← Back</button>
              <button onClick={next} style={{ flex:2, padding:'11px', background:'#1a2e2b', border:'none', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer' }}>Next →</button>
            </div>
          </div>
        )}

        {/* CONFIRM step */}
        {cur?.key==='confirm'&&(
          <div style={{ display:'grid', gap:'12px' }}>
            <h3 style={{ fontSize:'18px', fontFamily:'Georgia,serif', color:'#1a2e2b' }}>{isWakeUp?'Ready to re-engage?':'Process this lead?'}</h3>
            <div style={{ background:'rgba(168,201,196,0.06)', border:'1px solid rgba(168,201,196,0.2)', borderRadius:'10px', padding:'12px 14px', display:'grid', gap:'8px' }}>
              {[
                { label:'Lead', val:person.name },
                { label:'Project', val:project||person.project||'—' },
                { label:'Drip path', val:(pathId==='none'?'No drip emails':(()=>{ const id=pathId||defPathId; return DRIP_PATHS_CONFIG.find(p=>p.id===id)?.name||id })()) },
                { label:'New stage', val:'Attempting to Contact' },
              ].map(r=>(
                <div key={r.label} style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                  <p style={{ fontSize:'12px', color:'#8a9e9a' }}>{r.label}</p>
                  <p style={{ fontSize:'12px', fontWeight:600, color:'#1a2e2b' }}>{r.val}</p>
                </div>
              ))}
            </div>
            <div style={{ display:'flex', gap:'8px' }}>
              <button onClick={back} style={{ flex:1, padding:'11px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', color:'#8a9e9a', cursor:'pointer' }}>← Back</button>
              <button onClick={finish} style={{ flex:2, padding:'11px', background:'#22c55e', border:'none', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer' }}>
                {(pathId==='none')
                  ? (isWakeUp?'✅ Re-activate (no drip)':'✅ Process lead (no drip)')
                  : (isWakeUp?'✅ Re-activate & start drip':'✅ Process lead & start drip')
                }
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

function NoteCard({ note, color, bg, border, accent, textColor, extra, onEdit, onDelete }) {
  const [editing, setEditing] = useState(false)
  const [val, setVal]         = useState(note.text)
  const [confirm, setConfirm] = useState(false)

  function save() { if(val.trim()) onEdit(val.trim()); setEditing(false) }

  return (
    <div style={{ padding:'10px 12px', background:bg, border:`1px solid ${border}`, borderRadius:'9px', borderLeft:`3px solid ${accent}`, marginBottom:'6px' }}>
      {editing ? (
        <div style={{ display:'grid', gap:'6px' }}>
          <textarea autoFocus value={val} onChange={e=>setVal(e.target.value)}
            style={{ width:'100%', padding:'6px 8px', border:`1.5px solid ${color}50`, borderRadius:'7px', fontSize:'13px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', resize:'none', minHeight:'64px', boxSizing:'border-box' }} />
          <div style={{ display:'flex', gap:'6px' }}>
            <button onClick={()=>setEditing(false)} style={{ flex:1, padding:'5px', background:'transparent', border:'1px solid rgba(0,0,0,0.1)', borderRadius:'7px', fontSize:'12px', fontFamily:'inherit', color:'#8a9e9a', cursor:'pointer' }}>Cancel</button>
            <button onClick={save} style={{ flex:2, padding:'5px', background:'#1a2e2b', border:'none', borderRadius:'7px', fontSize:'12px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer' }}>Save</button>
          </div>
        </div>
      ) : (
        <>
          <p style={{ fontSize:'13px', color:textColor, lineHeight:1.45 }}>{note.text}</p>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginTop:'4px' }}>
            <div style={{ display:'flex', gap:'6px', alignItems:'center' }}>
              <p style={{ fontSize:'10px', color:color, opacity:0.7 }}>{note.ts} · {note.user}{note.edited?' · edited':''}</p>
              {extra}
            </div>
            <div style={{ display:'flex', gap:'4px' }}>
              {!confirm ? (
                <>
                  <button onClick={()=>{ setEditing(true); setVal(note.text) }} style={{ fontSize:'11px', color:'#8a9e9a', background:'none', border:'none', cursor:'pointer', padding:'1px 5px' }}>Edit</button>
                  <button onClick={()=>setConfirm(true)} style={{ fontSize:'11px', color:'#ef4444', background:'none', border:'none', cursor:'pointer', padding:'1px 5px' }}>Delete</button>
                </>
              ) : (
                <>
                  <button onClick={()=>setConfirm(false)} style={{ fontSize:'11px', color:'#8a9e9a', background:'none', border:'none', cursor:'pointer', padding:'1px 5px' }}>Cancel</button>
                  <button onClick={onDelete} style={{ fontSize:'11px', color:'white', background:'#ef4444', border:'none', borderRadius:'5px', cursor:'pointer', padding:'2px 7px', fontFamily:'inherit' }}>Confirm delete</button>
                </>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  )
}

function SnoozePopup({ person, onSave, onClose }) {
  const [date, setDate] = useState('')
  const [note, setNote] = useState(person.snoozeNote||'')
  const presets = [
    { label:'2 weeks', days:14 },
    { label:'1 month', days:30 },
    { label:'3 months', days:90 },
    { label:'6 months', days:180 },
  ]
  function pickPreset(days) {
    const d = new Date(); d.setDate(d.getDate()+days)
    setDate(d.toISOString().split('T')[0])
  }
  const canSave = !!date

  return (
    <div style={{ position:'fixed', inset:0, zIndex:10003, display:'flex', alignItems:'center', justifyContent:'center', padding:'12px' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(26,46,43,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', width:'100%', maxWidth:'440px', borderRadius:'20px', padding:'1.5rem', zIndex:1, boxShadow:'0 20px 60px rgba(26,46,43,0.25)' }}>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'4px' }}>
          <h3 style={{ fontSize:'18px', fontFamily:'Georgia,serif', color:'#1a2e2b' }}>💤 Snooze Lead</h3>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'20px', color:'#8a9e9a', cursor:'pointer' }}>×</button>
        </div>
        <p style={{ fontSize:'12px', color:'#8a9e9a', marginBottom:'14px' }}>Move to Nurturing and wake up in Needs Attention on the date you pick.</p>

        {/* Presets */}
        <div style={{ display:'flex', gap:'6px', marginBottom:'10px', flexWrap:'wrap' }}>
          {presets.map(p=>(
            <button key={p.days} onClick={()=>pickPreset(p.days)}
              style={{ padding:'6px 14px', borderRadius:'20px', border:'1.5px solid rgba(0,0,0,0.1)', background:'white', fontSize:'12px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer', fontWeight:500 }}>
              {p.label}
            </button>
          ))}
        </div>

        {/* Custom date */}
        <input type="date" value={date} onChange={e=>setDate(e.target.value)}
          min={new Date().toISOString().split('T')[0]}
          style={{ width:'100%', padding:'10px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'9px', fontSize:'14px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', marginBottom:'10px', boxSizing:'border-box' }} />

        {date&&<p style={{ fontSize:'12px', color:'#a8c9c4', marginBottom:'10px', textAlign:'center' }}>
          ⏰ Wakes up {new Date(date+'T00:00:00').toLocaleDateString('en-US',{weekday:'long',month:'long',day:'numeric'})}
        </p>}

        <textarea value={note} onChange={e=>setNote(e.target.value)} placeholder='Why snoozed? (e.g. "Renovating until July, call back then")' rows={2}
          style={{ width:'100%', padding:'9px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'9px', fontSize:'13px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', resize:'none', boxSizing:'border-box', marginBottom:'12px' }} />

        <div style={{ display:'flex', gap:'8px' }}>
          <button onClick={onClose} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
          <button onClick={()=>canSave&&onSave(date,note)} disabled={!canSave}
            style={{ flex:2, padding:'12px', background:canSave?'#1a2e2b':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'13px', fontFamily:'inherit', fontWeight:600, color:canSave?'white':'#9ca3af', cursor:canSave?'pointer':'not-allowed' }}>
            💤 Snooze until {date?new Date(date+'T00:00:00').toLocaleDateString('en-US',{month:'short',day:'numeric'}):'...'}
          </button>
        </div>
      </div>
    </div>
  )
}

function ClosePopup({ person, onConfirm, onClose }) {
  const [step, setStep] = useState('reason')
  const [reason, setReason] = useState('')
  const [note, setNote] = useState('')
  const [scheduleFollowUp, setScheduleFollowUp] = useState(false)
  const [followUpDate, setFollowUpDate] = useState('')
  const [followUpNote, setFollowUpNote] = useState('')
  const reasons = getCloseLostReasons()||DEFAULT_CLOSE_REASONS
  const needsNote = reason === 'Other'
  const canConfirm = reason && (!needsNote || note.trim().length > 0)

  return (
    <Popup title={step==='reason'?`Close - ${person.name}`:'Schedule Follow-Up'} onClose={onClose}>
      {step==='reason'&&(
        <>
          <p style={{ fontSize:'13px', color:'#8a9e9a', marginBottom:'1rem' }}>
            Select a reason. This moves them to your Closed view and can be restored anytime.
          </p>
          <div style={{ display:'grid', gap:'6px', marginBottom: reason ? '1rem' : '1.25rem' }}>
            {reasons.map(r=>(
              <button key={r} onClick={()=>{ setReason(r); setNote('') }}
                style={{ padding:'10px 14px', background:reason===r?'rgba(26,46,43,0.06)':'white', border:`1.5px solid ${reason===r?'rgba(26,46,43,0.3)':'rgba(0,0,0,0.08)'}`, borderRadius:'9px', cursor:'pointer', textAlign:'left', fontFamily:'inherit', fontSize:'13px', color:reason===r?'#1a2e2b':'#4a5e5a', fontWeight:reason===r?600:400, display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                {r}
                {r==='Other' && <span style={{ fontSize:'10px', color:'#8a9e9a', fontWeight:400 }}>Note required</span>}
              </button>
            ))}
          </div>
          {reason&&(
            <div style={{ marginBottom:'1.25rem' }}>
              <textarea value={note} onChange={e=>setNote(e.target.value)}
                placeholder={reason==='Other'?'Please describe the reason for closing...':'Optional - any notes?'}
                autoFocus={reason==='Other'}
                style={{...inp, height:'80px', resize:'none', borderColor: needsNote && !note.trim() ? 'rgba(212,160,70,0.5)' : 'rgba(0,0,0,0.1)'}} />
              {needsNote && !note.trim() && <p style={{ fontSize:'11px', color:'#d4a046', marginTop:'4px' }}>A note is required for this reason.</p>}
            </div>
          )}
          <div style={{ display:'flex', gap:'10px' }}>
            <button onClick={onClose} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
            <button onClick={()=>canConfirm&&setStep('followup')} disabled={!canConfirm}
              style={{ flex:2, padding:'12px', background:canConfirm?'#1a2e2b':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:canConfirm?'white':'#9ca3af', cursor:canConfirm?'pointer':'not-allowed' }}>
              Next →
            </button>
          </div>
        </>
      )}

      {step==='followup'&&(
        <>
          <p style={{ fontSize:'13px', color:'#8a9e9a', marginBottom:'1rem' }}>Not the right time - want to set a reminder to follow up later?</p>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'10px', marginBottom:'1rem' }}>
            <button onClick={()=>setScheduleFollowUp(true)} style={{ padding:'14px 12px', background:scheduleFollowUp?'rgba(168,201,196,0.12)':'#f7f5f0', border:`2px solid ${scheduleFollowUp?'#a8c9c4':'rgba(0,0,0,0.08)'}`, borderRadius:'12px', cursor:'pointer', fontFamily:'inherit', textAlign:'center' }}>
              <p style={{ fontSize:'18px', marginBottom:'3px' }}>📅</p>
              <p style={{ fontSize:'12px', fontWeight:600, color:'#1a2e2b' }}>Yes, remind me</p>
            </button>
            <button onClick={()=>{ setScheduleFollowUp(false); setFollowUpDate(''); setFollowUpNote('') }} style={{ padding:'14px 12px', background:!scheduleFollowUp?'rgba(0,0,0,0.04)':'#f7f5f0', border:`2px solid ${!scheduleFollowUp?'rgba(0,0,0,0.2)':'rgba(0,0,0,0.08)'}`, borderRadius:'12px', cursor:'pointer', fontFamily:'inherit', textAlign:'center' }}>
              <p style={{ fontSize:'18px', marginBottom:'3px' }}>⏭</p>
              <p style={{ fontSize:'12px', fontWeight:600, color:'#1a2e2b' }}>Skip for now</p>
            </button>
          </div>
          {scheduleFollowUp&&(
            <div style={{ display:'grid', gap:'8px', marginBottom:'1rem' }}>
              <input type="date" value={followUpDate} onChange={e=>setFollowUpDate(e.target.value)}
                min={new Date().toISOString().split('T')[0]}
                style={{ width:'100%', padding:'9px 11px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'13px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box' }} />
              <input value={followUpNote} onChange={e=>setFollowUpNote(e.target.value)} placeholder="Reason (e.g. Check in spring 2027)"
                style={{ width:'100%', padding:'9px 11px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'13px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box' }} />
            </div>
          )}
          <div style={{ display:'flex', gap:'10px' }}>
            <button onClick={()=>setStep('reason')} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>← Back</button>
            <button onClick={()=>onConfirm(reason, note.trim(), scheduleFollowUp&&followUpDate?{date:followUpDate,note:followUpNote}:null)}
              disabled={scheduleFollowUp&&!followUpDate}
              style={{ flex:2, padding:'12px', background:(!scheduleFollowUp||followUpDate)?'#1a2e2b':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:(!scheduleFollowUp||followUpDate)?'white':'#9ca3af', cursor:(!scheduleFollowUp||followUpDate)?'pointer':'not-allowed' }}>
              Close Record
            </button>
          </div>
        </>
      )}
    </Popup>
  )
}


