// ─── Custom Path Builder ──────────────────────────────────────────────────────
const DELAY_OPTIONS = ['Immediately','1 day later','2 days later','3 days later','4 days later','5 days later','7 days later','10 days later','14 days later']

function CustomPathBuilder({ templates, onSave, onClose, smsEnabled=true }) {
  const [pathName, setPathName] = useState('')
  const [projectType, setProjectType] = useState('any')
  const [steps, setSteps] = useState([
    { id:`cs${Date.now()}`, order:1, name:'', type:'email', delay:'Immediately', templateId:null }
  ])
  const [pickingTemplateFor, setPickingTemplateFor] = useState(null)

  const typeConf = {
    email:{ icon:'📧', color:'#6366f1' },
    sms:  { icon:'💬', color:'#10b981' },
    call: { icon:'📞', color:'#f59e0b' },
  }

  function addStep() {
    setSteps(prev=>[...prev, {
      id:`cs${Date.now()}`,
      order:prev.length+1,
      name:'',
      type:'email',
      delay:'Immediately',
      templateId:null
    }])
  }

  function removeStep(id) {
    setSteps(prev=>prev.filter(s=>s.id!==id).map((s,i)=>({...s,order:i+1})))
  }

  function updateStep(id, key, val) {
    setSteps(prev=>prev.map(s=>s.id===id?{...s,[key]:val}:s))
  }

  function assignTemplate(stepId, templateId) {
    updateStep(stepId, 'templateId', templateId)
    setPickingTemplateFor(null)
  }

  function save() {
    if (!pathName.trim()) return
    const pathId = `custom-${Date.now()}`
    onSave({ pathId, pathName, projectType, steps })
  }

  const canSave = pathName.trim() && steps.length > 0 && steps.every(s=>s.name.trim())

  return (
    <div style={{ position:'fixed', top:0, left:0, right:0, bottom:0, zIndex:10005, display:'flex', alignItems:'flex-end' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(26,46,43,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', width:'100%', maxWidth:'540px', borderRadius:'16px', zIndex:1, height:'88vh', display:'flex', flexDirection:'column', boxShadow:'0 -8px 40px rgba(26,46,43,0.2)' }}>
        {/* Header */}
        <div style={{ padding:'0.75rem 1.25rem', borderBottom:'1px solid rgba(0,0,0,0.06)', flexShrink:0 }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between' }}>
            <h3 style={{ fontSize:'16px', fontFamily:'Georgia,serif', color:'#1a2e2b' }}>Custom Path Builder</h3>
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'20px', color:'#8a9e9a', cursor:'pointer' }}>×</button>
          </div>
        </div>

        <div style={{ flex:1, overflowY:'auto', padding:'1rem 1.25rem', display:'grid', gap:'14px' }}>

          {/* Path name */}
          <div>
            <label style={{ fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px', display:'block', marginBottom:'5px' }}>Path Name</label>
            <input
              autoFocus value={pathName} onChange={e=>setPathName(e.target.value)}
              placeholder='e.g. VIP Concierge, Referral Fast-Track...'
              style={{ width:'100%', padding:'10px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'16px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box' }}
            />
          </div>

          {/* Project type */}
          <div>
            <label style={{ fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px', display:'block', marginBottom:'6px' }}>Applies To</label>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:'7px' }}>
              {[['any','🌐','All Leads'],['move','📦','Move Only'],['general','🏠','General Only']].map(([v,icon,label])=>(
                <button key={v} onClick={()=>setProjectType(v)} style={{ padding:'9px', borderRadius:'9px', cursor:'pointer', border:'2px solid', borderColor:projectType===v?'#a8c9c4':'rgba(0,0,0,0.08)', background:projectType===v?'rgba(168,201,196,0.12)':'white', fontFamily:'inherit', display:'flex', flexDirection:'column', alignItems:'center', gap:'4px' }}>
                  <span style={{ fontSize:'18px' }}>{icon}</span>
                  <span style={{ fontSize:'11px', fontWeight:projectType===v?600:400, color:'#1a2e2b' }}>{label}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Steps */}
          <div>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'8px' }}>
              <label style={{ fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px' }}>Steps ({steps.length})</label>
              <button onClick={addStep} style={{ fontSize:'12px', color:'#1a2e2b', background:'rgba(168,201,196,0.15)', border:'1px solid rgba(168,201,196,0.3)', borderRadius:'6px', padding:'4px 10px', cursor:'pointer', fontFamily:'inherit', fontWeight:600 }}>+ Add Step</button>
            </div>

            <div style={{ display:'grid', gap:'8px' }}>
              {steps.map((step, i)=>{
                const tc = typeConf[step.type]
                const tmpl = templates.find(t=>t.id===step.templateId)
                return (
                  <div key={step.id} style={{ background:'#f7f5f0', borderRadius:'10px', padding:'12px', border:'1px solid rgba(0,0,0,0.07)' }}>
                    {/* Step header */}
                    <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'10px' }}>
                      <div style={{ width:'22px', height:'22px', borderRadius:'50%', background:'#1a2e2b', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                        <span style={{ fontSize:'11px', color:'white', fontWeight:700 }}>{step.order}</span>
                      </div>
                      <input
                        value={step.name} onChange={e=>updateStep(step.id,'name',e.target.value)}
                        placeholder={`Step ${step.order} name...`}
                        style={{ flex:1, padding:'6px 10px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'7px', fontSize:'13px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', background:'white' }}
                      />
                      <button onClick={()=>removeStep(step.id)} style={{ fontSize:'16px', color:'#c8d8d4', background:'none', border:'none', cursor:'pointer', flexShrink:0 }}>×</button>
                    </div>

                    {/* Type + Delay */}
                    <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'7px', marginBottom:'8px' }}>
                      <div>
                        <p style={{ fontSize:'10px', color:'#8a9e9a', fontWeight:600, textTransform:'uppercase', letterSpacing:'0.4px', marginBottom:'4px' }}>Type</p>
                        <div style={{ display:'flex', gap:'5px' }}>
                          {Object.entries(typeConf).filter(([v])=>v!=='sms'||smsEnabled).map(([v,conf])=>(
                            <button key={v} onClick={()=>{ updateStep(step.id,'type',v); updateStep(step.id,'templateId',null) }} style={{ flex:1, padding:'6px', borderRadius:'7px', cursor:'pointer', border:'1.5px solid', borderColor:step.type===v?conf.color:'rgba(0,0,0,0.08)', background:step.type===v?`${conf.color}12`:'white', fontSize:'14px', display:'flex', alignItems:'center', justifyContent:'center' }}>
                              {conf.icon}
                            </button>
                          ))}
                        </div>
                      </div>
                      <div>
                        <p style={{ fontSize:'10px', color:'#8a9e9a', fontWeight:600, textTransform:'uppercase', letterSpacing:'0.4px', marginBottom:'4px' }}>Send</p>
                        <select value={step.delay} onChange={e=>updateStep(step.id,'delay',e.target.value)} style={{ width:'100%', padding:'6px 8px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'7px', fontSize:'12px', fontFamily:'inherit', color:'#1a2e2b', background:'white', outline:'none', appearance:'none' }}>
                          {DELAY_OPTIONS.map(d=><option key={d}>{d}</option>)}
                        </select>
                      </div>
                    </div>

                    {/* Template picker */}
                    <button onClick={()=>setPickingTemplateFor(step.id)} style={{ width:'100%', padding:'8px 12px', background:tmpl?'rgba(99,102,241,0.06)':'white', border:`1.5px solid ${tmpl?'rgba(99,102,241,0.2)':'rgba(0,0,0,0.1)'}`, borderRadius:'8px', cursor:'pointer', fontFamily:'inherit', display:'flex', alignItems:'center', gap:'8px', textAlign:'left' }}>
                      <span style={{ fontSize:'14px' }}>{tc.icon}</span>
                      <div style={{ flex:1, minWidth:0 }}>
                        <p style={{ fontSize:'12px', fontWeight:tmpl?600:400, color:tmpl?'#6366f1':'#8a9e9a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                          {tmpl ? tmpl.name : 'Tap to pick a template'}
                        </p>
                        {tmpl&&<p style={{ fontSize:'10px', color:'#8a9e9a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{tmpl.type==='email'&&tmpl.subject?tmpl.subject:tmpl.body.slice(0,45)+'...'}</p>}
                      </div>
                      <span style={{ fontSize:'11px', color:'#c8d8d4', flexShrink:0 }}>›</span>
                    </button>
                  </div>
                )
              })}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div style={{ padding:'1rem 1.25rem', borderTop:'1px solid rgba(0,0,0,0.06)', display:'flex', gap:'10px', flexShrink:0 }}>
          <button onClick={onClose} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
          <button onClick={save} disabled={!canSave} style={{ flex:2, padding:'12px', background:canSave?'#1a2e2b':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:canSave?'white':'#9ca3af', cursor:canSave?'pointer':'not-allowed' }}>
            ✅ Save Path
          </button>
        </div>
      </div>

      {/* Template picker for step */}
      {pickingTemplateFor&&(
        <StepTemplatePicker
          step={steps.find(s=>s.id===pickingTemplateFor)}
          templates={templates}
          smsEnabled={smsEnabled}
          onSelect={tid=>assignTemplate(pickingTemplateFor, tid)}
          onClose={()=>setPickingTemplateFor(null)}
        />
      )}
    </div>
  )
}

// ─── Template Editor Popup ────────────────────────────────────────────────────
function TemplateEditorPopup({ template, isNew=false, isMasterEdit=false, onSave, onClose }) {
  const [name, setName]       = useState(template?.name||'')
  const [type, setType]       = useState(template?.type||'email')
  const [subject, setSubject] = useState(template?.subject||'')
  const [body, setBody]       = useState(template?.body||'')
  const [tab, setTab]         = useState('edit') // 'edit' | 'preview'
  const textareaRef = useRef(null)

  function insertVariable(key) {
    const el = textareaRef.current
    if (!el) return
    const start = el.selectionStart, end = el.selectionEnd
    const newBody = body.slice(0,start) + key + body.slice(end)
    setBody(newBody)
    setTimeout(()=>{ el.focus(); el.setSelectionRange(start+key.length, start+key.length) }, 0)
  }

  function preview(text) {
    return text
      .replace(/\{\{first_name\}\}/g, 'Sarah')
      .replace(/\{\{last_name\}\}/g, 'Mitchell')
      .replace(/\{\{organizer_name\}\}/g, 'Kevin Shaw')
      .replace(/\{\{location_name\}\}/g, 'Denver')
      .replace(/\{\{booking_link\}\}/g, 'https://beehub.io/book/denver')
      .replace(/\{\{phone\}\}/g, '(303) 555-0200')
      .replace(/\{\{service_area\}\}/g, 'Denver Metro')
  }

  const typeConf = { email:{icon:'📧',color:'#6366f1'}, sms:{icon:'💬',color:'#10b981'}, call:{icon:'📞',color:'#f59e0b'} }
  const tc = typeConf[type]

  return (
    <div style={{ position:'fixed', top:0, left:0, right:0, bottom:0, zIndex:10005, display:'flex', alignItems:'flex-end' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(26,46,43,0.5)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', width:'100%', maxWidth:'540px', borderRadius:'16px', zIndex:1, height:'88vh', display:'flex', flexDirection:'column', boxShadow:'0 -8px 40px rgba(26,46,43,0.2)' }}>
        {/* Header */}
        <div style={{ padding:'0.75rem 1.25rem 0', borderBottom:'1px solid rgba(0,0,0,0.06)', flexShrink:0 }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:'10px' }}>
            <h3 style={{ fontSize:'16px', fontFamily:'Georgia,serif', color:'#1a2e2b' }}>{isNew?'New Template': isMasterEdit?'Edit Master Template':'Customize Template'}</h3>
            <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'20px', color:'#8a9e9a', cursor:'pointer' }}>×</button>
          </div>
          <div style={{ display:'flex', gap:'0' }}>
            {['edit','preview'].map(t=>(
              <button key={t} onClick={()=>setTab(t)} style={{ flex:1, padding:'8px', border:'none', cursor:'pointer', fontFamily:'inherit', fontSize:'13px', fontWeight:tab===t?600:400, background:'transparent', color:tab===t?'#1a2e2b':'#8a9e9a', borderBottom:`2px solid ${tab===t?'#a8c9c4':'transparent'}` }}>
                {t==='edit'?'Edit':'Preview'}
              </button>
            ))}
          </div>
        </div>

        {isMasterEdit&&(
          <div style={{ margin:'12px 16px 0', padding:'8px 12px', background:'rgba(212,160,70,0.08)', border:'1px solid rgba(212,160,70,0.25)', borderRadius:'9px', display:'flex', gap:'8px', alignItems:'flex-start' }}>
            <span style={{ fontSize:'14px' }}>⚠️</span>
            <p style={{ fontSize:'11px', color:'#c8a050', lineHeight:1.5 }}>You're editing a <strong>master template</strong>. Changes become the new default for all locations that haven't customized their copy.</p>
          </div>
        )}

        <div style={{ flex:1, overflowY:'auto', padding:'1rem 1.25rem', display:'grid', gap:'12px' }}>
          {tab==='edit'&&(
            <>
              {/* Name */}
              <div>
                <label style={{ fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px', display:'block', marginBottom:'5px' }}>Template Name</label>
                <input value={name} onChange={e=>setName(e.target.value)} placeholder='e.g. Welcome Email' style={{ width:'100%', padding:'10px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'16px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box' }} />
              </div>

              {/* Type */}
              <div>
                <label style={{ fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px', display:'block', marginBottom:'5px' }}>Type</label>
                <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:'8px' }}>
                  {[['email','📧','Email'],['sms','💬','SMS'],['call','📞','Call Script']].map(([v,icon,label])=>(
                    <button key={v} onClick={()=>setType(v)} style={{ padding:'10px', borderRadius:'9px', cursor:'pointer', border:'2px solid', borderColor:type===v?typeConf[v].color:'rgba(0,0,0,0.08)', background:type===v?`${typeConf[v].color}12`:'white', fontFamily:'inherit', display:'flex', flexDirection:'column', alignItems:'center', gap:'4px' }}>
                      <span style={{ fontSize:'18px' }}>{icon}</span>
                      <span style={{ fontSize:'11px', fontWeight:type===v?600:400, color:type===v?typeConf[v].color:'#4a5e5a' }}>{label}</span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Subject (email only) */}
              {type==='email'&&(
                <div>
                  <label style={{ fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px', display:'block', marginBottom:'5px' }}>Subject Line</label>
                  <input value={subject} onChange={e=>setSubject(e.target.value)} placeholder='e.g. Welcome, {{first_name}} 🐝' style={{ width:'100%', padding:'10px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'16px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box' }} />
                </div>
              )}

              {/* Variables */}
              <div>
                <label style={{ fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px', display:'block', marginBottom:'6px' }}>Insert Variable</label>
                <div style={{ display:'flex', gap:'5px', flexWrap:'wrap' }}>
                  {TEMPLATE_VARIABLES.map(v=>(
                    <button key={v.key} onClick={()=>insertVariable(v.key)} style={{ padding:'4px 9px', borderRadius:'20px', cursor:'pointer', border:'1px solid rgba(99,102,241,0.25)', background:'rgba(99,102,241,0.06)', fontSize:'11px', fontFamily:'inherit', color:'#6366f1', fontWeight:500 }}>
                      {v.label}
                    </button>
                  ))}
                </div>
              </div>

              {/* Body */}
              <div>
                <label style={{ fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px', display:'block', marginBottom:'5px' }}>
                  {type==='call'?'Script / Notes':'Message Body'}
                </label>
                <textarea
                  ref={textareaRef}
                  value={body}
                  onChange={e=>setBody(e.target.value)}
                  placeholder={type==='sms'?'Keep it brief and friendly...':type==='call'?'Write your call script or talking points...':'Write your email body here...'}
                  style={{ width:'100%', padding:'10px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'13px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box', height:type==='sms'?'100px':'200px', resize:'vertical', lineHeight:1.6 }}
                />
                <p style={{ fontSize:'11px', color:'#b0c0bc', marginTop:'4px' }}>{body.length} chars{type==='sms'&&body.length>160?<span style={{ color:'#f59e0b' }}> · exceeds 1 SMS</span>:''}</p>
              </div>
            </>
          )}

          {tab==='preview'&&(
            <div>
              <div style={{ padding:'8px 12px', background:'rgba(99,102,241,0.06)', border:'1px solid rgba(99,102,241,0.12)', borderRadius:'8px', marginBottom:'12px', fontSize:'11px', color:'#6366f1' }}>
                Previewing with: <strong>Sarah Mitchell</strong> · Denver location
              </div>
              {type==='email'&&(
                <div style={{ background:'white', borderRadius:'10px', overflow:'hidden', border:'1px solid rgba(0,0,0,0.08)' }}>
                  <div style={{ background:'#1a2e2b', padding:'12px 16px', textAlign:'center' }}>
                    <p style={{ color:'rgba(168,201,196,0.6)', fontSize:'10px', letterSpacing:'1px', textTransform:'uppercase', marginBottom:'2px' }}>Bee Organized</p>
                    <p style={{ color:'white', fontSize:'16px' }}>🐝</p>
                  </div>
                  {subject&&(
                    <div style={{ padding:'14px 16px 0' }}>
                      <p style={{ fontSize:'16px', fontWeight:700, color:'#1a2e2b', fontFamily:'Georgia,serif' }}>{preview(subject)}</p>
                    </div>
                  )}
                  <div style={{ padding:'14px 16px' }}>
                    <p style={{ fontSize:'13px', color:'#374151', lineHeight:1.8, whiteSpace:'pre-wrap' }}>{preview(body)||<span style={{ color:'#c8d8d4' }}>Write your email body above</span>}</p>
                  </div>
                  <div style={{ background:'#f7f5f0', padding:'12px 16px', borderTop:'1px solid #e5e7eb', textAlign:'center' }}>
                    <p style={{ fontSize:'10px', color:'#8a9e9a' }}>Bee Organized Denver · hello@beeorganized.com</p>
                    <p style={{ fontSize:'10px', color:'#b0c0bc', marginTop:'2px' }}>Unsubscribe · View in browser</p>
                  </div>
                </div>
              )}
              {type==='sms'&&(
                <div style={{ maxWidth:'280px' }}>
                  <div style={{ background:'#1a2e2b', borderRadius:'14px', padding:'10px 14px', marginLeft:'15%' }}>
                    <p style={{ fontSize:'14px', color:'white', lineHeight:1.6, whiteSpace:'pre-wrap' }}>{preview(body)||'...'}</p>
                  </div>
                  <p style={{ fontSize:'10px', color:'#8a9e9a', textAlign:'right', marginTop:'4px' }}>Delivered · Bee Organized</p>
                </div>
              )}
              {type==='call'&&(
                <div style={{ background:'white', borderRadius:'10px', padding:'16px', border:'1px solid rgba(0,0,0,0.08)' }}>
                  <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'12px', paddingBottom:'10px', borderBottom:'1px solid rgba(0,0,0,0.06)' }}>
                    <span style={{ fontSize:'20px' }}>📞</span>
                    <p style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b' }}>Call Script · {name||'Untitled'}</p>
                  </div>
                  <p style={{ fontSize:'13px', color:'#374151', lineHeight:1.8, whiteSpace:'pre-wrap' }}>{preview(body)||'Write your script above'}</p>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{ padding:'1rem 1.25rem', borderTop:'1px solid rgba(0,0,0,0.06)', display:'flex', gap:'10px', flexShrink:0 }}>
          <button onClick={onClose} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
          <button onClick={()=>name.trim()&&body.trim()&&onSave({ name, type, subject, body })} disabled={!name.trim()||!body.trim()} style={{ flex:2, padding:'12px', background:name.trim()&&body.trim()?'#1a2e2b':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:name.trim()&&body.trim()?'white':'#9ca3af', cursor:name.trim()&&body.trim()?'pointer':'not-allowed' }}>
            Save Template
          </button>
        </div>
      </div>
    </div>
  )
}

// ─── Template Editor Popup ────────────────────────────────────────────────────

function StepTemplatePicker({ step, templates, onSelect, onClose, smsEnabled=true }) {
  const [search, setSearch] = useState('')
  const compatible = templates.filter(t =>
    t.type === step.type &&
    (smsEnabled || t.type !== 'sms') &&
    (!search || t.name.toLowerCase().includes(search.toLowerCase()))
  )
  return (
    <div style={{ position:'fixed', inset:0, zIndex:10004, display:'flex', alignItems:'flex-end', justifyContent:'center' }}>
      <div style={{ position:'absolute', inset:0, background:'rgba(26,46,43,0.45)' }} onClick={onClose} />
      <div style={{ position:'relative', background:'white', width:'100%', borderRadius:'20px 20px 0 0', padding:'1rem', zIndex:1, maxHeight:'80vh', display:'flex', flexDirection:'column', boxSizing:'border-box', overflowX:'hidden', boxShadow:'0 -8px 40px rgba(26,46,43,0.2)' }}>
        <div style={{ width:'36px', height:'4px', background:'rgba(0,0,0,0.12)', borderRadius:'2px', margin:'0 auto 1rem', flexShrink:0 }} />
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'10px', flexShrink:0 }}>
          <h3 style={{ fontSize:'16px', fontFamily:'Georgia,serif', color:'#1a2e2b' }}>Pick Template</h3>
          <button onClick={onClose} style={{ background:'none', border:'none', fontSize:'20px', color:'#8a9e9a', cursor:'pointer' }}>×</button>
        </div>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder='Search templates...' style={{ width:'100%', padding:'9px 12px', border:'1.5px solid rgba(0,0,0,0.09)', borderRadius:'9px', fontSize:'13px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box', marginBottom:'10px', flexShrink:0 }} />
        <div style={{ flex:1, overflowY:'auto', display:'grid', gap:'6px' }}>
          {compatible.length===0&&<p style={{ fontSize:'13px', color:'#8a9e9a', textAlign:'center', padding:'1rem' }}>No {step.type} templates found</p>}
          {compatible.map(t=>(
            <button key={t.id} onClick={()=>onSelect(t.id)} style={{ padding:'12px 14px', background:step.templateId===t.id?'rgba(168,201,196,0.12)':'white', border:`1.5px solid ${step.templateId===t.id?'#a8c9c4':'rgba(0,0,0,0.08)'}`, borderRadius:'10px', cursor:'pointer', fontFamily:'inherit', textAlign:'left' }}>
              <div style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'3px' }}>
                <span style={{ fontSize:'14px' }}>{t.type==='email'?'📧':t.type==='sms'?'💬':'📞'}</span>
                <span style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b' }}>{t.name}</span>
                {step.templateId===t.id&&<span style={{ marginLeft:'auto', color:'#a8c9c4' }}>✓ Current</span>}
              </div>
              <p style={{ fontSize:'12px', color:'#8a9e9a', marginLeft:'22px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                {t.type==='email'&&t.subject?t.subject:t.body.slice(0,60)+'...'}
              </p>
            </button>
          ))}
        </div>
      </div>
    </div>
  )
}

