// ─── Add Step Inline ──────────────────────────────────────────────────────────
const DELAY_OPTIONS_SHORT = ['Immediately','1 day later','2 days later','3 days later','4 days later','5 days later','7 days later','10 days later','14 days later']

function AddStepInline({ pathId, order, templates, onSave, onCancel, smsEnabled }) {
  const [name, setName]               = useState('')
  const [type, setType]               = useState('email')
  const [delay, setDelay]             = useState('Immediately')
  const [templateId, setTemplateId]   = useState(null)
  const [pickingTemplate, setPickingTemplate] = useState(false)

  const tmpl = templates.find(t=>t.id===templateId)
  const tc = { email:{icon:'📧',color:'#6366f1'}, sms:{icon:'💬',color:'#10b981'}, call:{icon:'📞',color:'#f59e0b'} }
  const canSave = name.trim()

  function save() {
    if (!canSave) return
    onSave({ id:`s${Date.now()}`, order, name:name.trim(), type, delay, templateId })
  }

  return (
    <>
      <div style={{ marginTop:'4px', padding:'10px 12px', background:'rgba(168,201,196,0.06)', border:'1.5px dashed rgba(168,201,196,0.4)', borderRadius:'10px', display:'grid', gap:'8px' }}>
        {/* Step name */}
        <input
          autoFocus
          value={name}
          onChange={e=>setName(e.target.value)}
          onKeyDown={e=>{ if(e.key==='Enter') save(); if(e.key==='Escape') onCancel() }}
          placeholder={`Step ${order} name...`}
          style={{ width:'100%', padding:'7px 10px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'7px', fontSize:'12px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box', background:'white' }}
        />

        {/* Type + Delay row */}
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'6px' }}>
          {/* Type picker */}
          <div style={{ display:'flex', gap:'4px' }}>
            {Object.entries(tc).filter(([v])=> v!=='sms'||smsEnabled).map(([v,conf])=>(
              <button key={v} onClick={()=>{ setType(v); setTemplateId(null) }} style={{ flex:1, padding:'6px', borderRadius:'6px', cursor:'pointer', border:'1.5px solid', borderColor:type===v?conf.color:'rgba(0,0,0,0.08)', background:type===v?`${conf.color}12`:'white', fontSize:'14px', display:'flex', alignItems:'center', justifyContent:'center' }}>
                {conf.icon}
              </button>
            ))}
          </div>
          {/* Delay */}
          <select value={delay} onChange={e=>setDelay(e.target.value)} style={{ padding:'6px 8px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'7px', fontSize:'11px', fontFamily:'inherit', color:'#1a2e2b', background:'white', outline:'none', appearance:'none' }}>
            {DELAY_OPTIONS_SHORT.map(d=><option key={d}>{d}</option>)}
          </select>
        </div>

        {/* Template picker */}
        <button onClick={()=>setPickingTemplate(true)} style={{ width:'100%', padding:'7px 10px', background:tmpl?'rgba(99,102,241,0.07)':'white', border:`1.5px solid ${tmpl?'rgba(99,102,241,0.2)':'rgba(0,0,0,0.1)'}`, borderRadius:'7px', cursor:'pointer', fontFamily:'inherit', display:'flex', alignItems:'center', gap:'6px', textAlign:'left' }}>
          <span style={{ fontSize:'13px' }}>{tc[type].icon}</span>
          <span style={{ fontSize:'11px', color:tmpl?'#6366f1':'#8a9e9a', fontWeight:tmpl?600:400, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', flex:1 }}>
            {tmpl ? tmpl.name : 'Tap to assign a template'}
          </span>
          <span style={{ fontSize:'10px', color:'#c8d8d4', flexShrink:0 }}>›</span>
        </button>

        {/* Actions */}
        <div style={{ display:'flex', gap:'6px' }}>
          <button onClick={onCancel} style={{ flex:1, padding:'7px', background:'transparent', border:'1px solid rgba(0,0,0,0.1)', borderRadius:'7px', fontSize:'12px', fontFamily:'inherit', color:'#8a9e9a', cursor:'pointer' }}>Cancel</button>
          <button onClick={save} disabled={!canSave} style={{ flex:2, padding:'7px', background:canSave?'#1a2e2b':'#e5e7eb', border:'none', borderRadius:'7px', fontSize:'12px', fontFamily:'inherit', fontWeight:500, color:canSave?'white':'#9ca3af', cursor:canSave?'pointer':'not-allowed' }}>
            ✓ Add Step
          </button>
        </div>
      </div>

      {pickingTemplate&&(
        <StepTemplatePicker
          step={{ type, templateId }}
          templates={templates}
          smsEnabled={smsEnabled}
          onSelect={id=>{ setTemplateId(id); setPickingTemplate(false) }}
          onClose={()=>setPickingTemplate(false)}
        />
      )}
    </>
  )
}


// ─── Jobber Connection Card ───────────────────────────────────────────────────
function JobberConnectionCard({ settings, updateLocation }) {
  const [status, setStatus] = useState(settings.location.jobberStatus||'connected')

  function handleReconnect() {
    setStatus('connecting')
    setTimeout(()=>{ setStatus('connected'); updateLocation('jobberStatus','connected') }, 2200)
  }

  const statusConf = {
    connected:    { color:'#22c55e', bg:'rgba(34,197,94,0.08)',  border:'rgba(34,197,94,0.2)',  icon:'✅', label:'Connected'     },
    disconnected: { color:'#ef4444', bg:'rgba(239,68,68,0.08)',  border:'rgba(239,68,68,0.2)',  icon:'❌', label:'Disconnected'  },
    connecting:   { color:'#f59e0b', bg:'rgba(245,158,11,0.08)', border:'rgba(245,158,11,0.2)', icon:'⏳', label:'Connecting...' },
  }
  const sc = statusConf[status]||statusConf.connected

  return (
    <div style={{ borderRadius:'12px', overflow:'hidden', margin:'0 12px', border:'1px solid rgba(0,0,0,0.07)', background:'white' }}>
      <div style={{ padding:'12px 14px', display:'flex', alignItems:'center', gap:'12px' }}>
        <div style={{ width:'34px', height:'34px', borderRadius:'8px', background:'rgba(255,107,53,0.1)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
          <span style={{ fontSize:'16px' }}>⚡</span>
        </div>
        <div style={{ flex:1, minWidth:0 }}>
          <p style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b', marginBottom:'1px' }}>Jobber</p>
          <p style={{ fontSize:'11px', color:'#8a9e9a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
            {status==='connected' ? `${settings.location.jobberAccountId||'Connected'} · synced May 5` : status==='connecting' ? 'Connecting...' : 'Connection lost'}
          </p>
        </div>
        {status==='connected' ? (
          <span style={{ fontSize:'11px', padding:'3px 9px', borderRadius:'20px', background:sc.bg, color:sc.color, border:`1px solid ${sc.border}`, fontWeight:600, flexShrink:0 }}>{sc.icon} {sc.label}</span>
        ) : (
          <button onClick={handleReconnect} style={{ padding:'6px 12px', background:'#1a2e2b', border:'none', borderRadius:'8px', fontSize:'11px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer', flexShrink:0 }}>
            {status==='connecting' ? 'Connecting…' : '⚡ Reconnect'}
          </button>
        )}
      </div>
      {status==='disconnected'&&(
        <div style={{ padding:'8px 14px 10px', borderTop:'1px solid rgba(0,0,0,0.05)', background:'rgba(239,68,68,0.03)' }}>
          <p style={{ fontSize:'11px', color:'#ef4444' }}>Connection lost - reconnect to resume syncing leads, jobs, and invoices.</p>
        </div>
      )}
    </div>
  )
}

// ─── Client Import Card ────────────────────────────────────────────────────────
function ClientImportCard({ isJobberConnected, locationId }) {
  const STORAGE_KEY = `import_complete_${locationId}`
  const [importState, setImportState] = useState(() => {
    try { return localStorage.getItem(STORAGE_KEY) || 'idle' } catch { return 'idle' }
  })
  const [progress, setProgress]     = useState(0)
  const [clientCount, setClientCount] = useState(0)
  const [skipped, setSkipped]       = useState(false)

  if (!isJobberConnected) return null
  if (importState === 'complete') return null
  if (skipped) return (
    <div style={{ margin:'0 12px', borderRadius:'12px', background:'white', border:'1px solid rgba(0,0,0,0.07)', padding:'12px 14px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
      <div style={{ display:'flex', alignItems:'center', gap:'10px' }}>
        <span style={{ fontSize:'16px' }}>📋</span>
        <div>
          <p style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b', marginBottom:'1px' }}>Client Import</p>
          <p style={{ fontSize:'11px', color:'#8a9e9a' }}>Skipped - tap to import when ready</p>
        </div>
      </div>
      <button onClick={()=>setSkipped(false)}
        style={{ padding:'6px 12px', background:'#1a2e2b', border:'none', borderRadius:'8px', fontSize:'11px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer' }}>
        Import Now
      </button>
    </div>
  )

  function startImport() {
    setImportState('running')
    setProgress(0)
    const total = Math.floor(Math.random() * 80) + 40
    let current = 0
    const interval = setInterval(() => {
      current += Math.floor(Math.random() * 8) + 2
      if (current >= total) {
        current = total
        clearInterval(interval)
        setProgress(100)
        setClientCount(total)
        setTimeout(() => {
          setImportState('complete')
          try { localStorage.setItem(STORAGE_KEY, 'complete') } catch {}
        }, 800)
      }
      setProgress(Math.round((current / total) * 100))
      setClientCount(current)
    }, 180)
  }

  return (
    <div style={{ margin:'0 12px', borderRadius:'12px', background:'white', border:'1px solid rgba(0,0,0,0.07)', overflow:'hidden' }}>
      {/* Header */}
      <div style={{ padding:'12px 14px', display:'flex', alignItems:'center', gap:'12px' }}>
        <div style={{ width:'34px', height:'34px', borderRadius:'8px', background:'rgba(168,201,196,0.15)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
          <span style={{ fontSize:'16px' }}>📋</span>
        </div>
        <div style={{ flex:1, minWidth:0 }}>
          <p style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b', marginBottom:'1px' }}>Import Clients from Jobber</p>
          <p style={{ fontSize:'11px', color:'#8a9e9a' }}>
            {importState==='idle' && 'Bring your existing clients into Bee Hub'}
            {importState==='running' && `Importing… ${clientCount} clients so far`}
          </p>
        </div>
        {importState==='idle' && (
          <button onClick={()=>setSkipped(true)}
            style={{ fontSize:'11px', color:'#8a9e9a', background:'none', border:'none', cursor:'pointer', fontFamily:'inherit', padding:'4px 8px', flexShrink:0 }}>
            Skip
          </button>
        )}
      </div>

      {/* Progress bar */}
      {importState==='running' && (
        <div style={{ padding:'0 14px 12px' }}>
          <div style={{ height:'6px', background:'rgba(168,201,196,0.2)', borderRadius:'3px', overflow:'hidden' }}>
            <div style={{ height:'100%', width:`${progress}%`, background:'linear-gradient(90deg,#1a2e2b,#a8c9c4)', borderRadius:'3px', transition:'width 0.2s ease' }} />
          </div>
          <p style={{ fontSize:'10px', color:'#8a9e9a', marginTop:'5px', textAlign:'right' }}>{progress}%</p>
        </div>
      )}

      {/* Action */}
      {importState==='idle' && (
        <div style={{ padding:'0 14px 12px' }}>
          <button onClick={startImport}
            style={{ width:'100%', padding:'10px', background:'#1a2e2b', border:'none', borderRadius:'9px', fontSize:'13px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer' }}>
            Start Import
          </button>
          <p style={{ fontSize:'10px', color:'#b0c0bc', textAlign:'center', marginTop:'6px' }}>Future client syncs happen automatically</p>
        </div>
      )}
    </div>
  )
}

// ─── Client Notifications Card ─────────────────────────────────────────────────
function LeadNotificationsCard({ settings, updateLocation, locationId, ownerEmail }) {
  const teamMembers = USERS_DATA.filter(u => u.locationId === locationId)
  const [checkedIds, setCheckedIds] = useState(() => {
    // Default: owner checked
    const owner = teamMembers.find(u => u.role === 'owner')
    return owner ? [owner.id] : []
  })
  const [extraEmails, setExtraEmails] = useState(
    settings.location.notifEmails?.filter(e => !teamMembers.find(u => u.email === e)) || []
  )
  const [adding, setAdding] = useState(false)
  const [newEmail, setNewEmail] = useState('')

  function toggleMember(id) {
    setCheckedIds(prev => prev.includes(id) ? prev.filter(x=>x!==id) : [...prev, id])
  }

  function addExtra() {
    if (!newEmail.trim().includes('@')) return
    setExtraEmails(prev => [...prev, newEmail.trim()])
    setNewEmail('')
    setAdding(false)
  }

  function removeExtra(i) {
    setExtraEmails(prev => prev.filter((_,idx) => idx !== i))
  }

  const totalCount = checkedIds.length + extraEmails.length

  return (
    <div style={{ margin:'0 12px', borderRadius:'12px', overflow:'hidden', boxShadow:'0 1px 4px rgba(0,0,0,0.06)' }}>

      {/* Team members */}
      {teamMembers.length > 0 && (
        <div style={{ background:'white' }}>
          <div style={{ padding:'8px 16px 4px', borderBottom:'1px solid rgba(0,0,0,0.05)' }}>
            <p style={{ fontSize:'10px', fontWeight:700, color:'#8a9e9a', textTransform:'uppercase', letterSpacing:'0.4px' }}>Team Members</p>
          </div>
          {teamMembers.map((u, i) => {
            const rc = FRANCHISE_ROLES.find(r => r.key === u.role)
            const checked = checkedIds.includes(u.id)
            return (
              <div key={u.id} onClick={() => toggleMember(u.id)} style={{ padding:'11px 16px', display:'flex', alignItems:'center', gap:'12px', borderBottom: i < teamMembers.length - 1 ? '1px solid rgba(0,0,0,0.04)' : 'none', cursor:'pointer', background: checked ? 'rgba(168,201,196,0.04)' : 'white' }}>
                <div style={{ width:'20px', height:'20px', borderRadius:'5px', border:`2px solid ${checked ? '#1a2e2b' : 'rgba(0,0,0,0.15)'}`, background: checked ? '#1a2e2b' : 'white', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                  {checked && <span style={{ color:'white', fontSize:'11px', fontWeight:700 }}>✓</span>}
                </div>
                <div style={{ width:'30px', height:'30px', borderRadius:'50%', background:'linear-gradient(135deg,#a8c9c4,#7ab5af)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'11px', fontWeight:700, color:'white', flexShrink:0 }}>{u.initials}</div>
                <div style={{ flex:1, minWidth:0 }}>
                  <p style={{ fontSize:'13px', fontWeight:600, color:'#1a2e2b', marginBottom:'1px' }}>{u.name}</p>
                  <p style={{ fontSize:'11px', color:'#8a9e9a', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{u.email}</p>
                </div>
                <span style={{ fontSize:'10px', padding:'2px 7px', borderRadius:'20px', background:rc?.bg, color:rc?.color, fontWeight:600, flexShrink:0 }}>{rc?.icon} {rc?.label}</span>
              </div>
            )
          })}
        </div>
      )}

      {/* Extra external emails */}
      {extraEmails.length > 0 && (
        <div style={{ background:'white', borderTop:'1px solid rgba(0,0,0,0.05)' }}>
          <div style={{ padding:'8px 16px 4px' }}>
            <p style={{ fontSize:'10px', fontWeight:700, color:'#8a9e9a', textTransform:'uppercase', letterSpacing:'0.4px' }}>Additional Emails</p>
          </div>
          {extraEmails.map((email, i) => (
            <div key={i} style={{ padding:'10px 16px', display:'flex', alignItems:'center', gap:'10px', borderTop:'1px solid rgba(0,0,0,0.04)' }}>
              <span style={{ fontSize:'14px' }}>✉️</span>
              <p style={{ flex:1, fontSize:'13px', color:'#1a2e2b', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{email}</p>
              <button onClick={() => removeExtra(i)} style={{ background:'none', border:'none', color:'#e5a0a0', cursor:'pointer', fontSize:'16px', flexShrink:0 }}>×</button>
            </div>
          ))}
        </div>
      )}

      {/* Add email / summary */}
      {adding ? (
        <div style={{ background:'#f7f5f0', padding:'10px 14px', display:'flex', gap:'8px', alignItems:'center', borderTop:'1px solid rgba(0,0,0,0.05)' }}>
          <input autoFocus value={newEmail} onChange={e=>setNewEmail(e.target.value)} onKeyDown={e=>{ if(e.key==='Enter') addExtra(); if(e.key==='Escape') setAdding(false) }} placeholder="email@example.com" type="email"
            style={{ flex:1, padding:'9px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'13px', fontFamily:'inherit', color:'#1a2e2b', outline:'none' }} />
          <button onClick={addExtra} style={{ padding:'9px 14px', background:'#1a2e2b', border:'none', borderRadius:'8px', fontSize:'12px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer' }}>Add</button>
          <button onClick={()=>setAdding(false)} style={{ padding:'9px 10px', background:'transparent', border:'1px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'12px', color:'#8a9e9a', cursor:'pointer', fontFamily:'inherit' }}>✕</button>
        </div>
      ) : (
        <div style={{ background:'white', borderTop:'1px solid rgba(0,0,0,0.05)', padding:'10px 16px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
          <span style={{ fontSize:'12px', color:'#8a9e9a' }}>{totalCount} recipient{totalCount !== 1 ? 's' : ''} selected</span>
          <button onClick={() => setAdding(true)} style={{ padding:'6px 12px', background:'transparent', border:'1px solid rgba(168,201,196,0.4)', borderRadius:'8px', fontSize:'12px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>+ Add email</button>
        </div>
      )}
    </div>
  )
}

// ─── SMS Add-on Card ──────────────────────────────────────────────────────────
// getSMSPrice() pulled from add-on pricing
function getSMSPrice() { return APP_ADDONS.find(a=>a.id==='sms')?.price || 100 }

function SmsAddonCard({ settings, updateLocation }) {
  const [showPayModal, setShowPayModal] = useState(false)
  const enabled = settings.location.smsEnabled
  const proration = calcProration(getSMSPrice())

  return (
    <>
      <div style={{ background:'white' }}>
        {/* Header */}
        <div style={{ padding:'14px 16px', display:'flex', alignItems:'center', gap:'12px' }}>
          <div style={{ width:'40px', height:'40px', borderRadius:'10px', background:'rgba(16,185,129,0.1)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
            <span style={{ fontSize:'20px' }}>💬</span>
          </div>
          <div style={{ flex:1 }}>
            <div style={{ display:'flex', alignItems:'center', gap:'6px', marginBottom:'2px' }}>
              <p style={{ fontSize:'14px', fontWeight:600, color:'#1a2e2b' }}>SMS Messaging</p>
              <span style={{ fontSize:'10px', color:'#d4a046', background:'rgba(212,160,70,0.1)', padding:'1px 7px', borderRadius:'20px', fontWeight:600 }}>Add-on</span>
              {enabled&&<span style={{ fontSize:'10px', color:'#22c55e', background:'rgba(34,197,94,0.1)', padding:'1px 7px', borderRadius:'20px', fontWeight:600 }}>✅ Active</span>}
            </div>
            <p style={{ fontSize:'12px', color:'#8a9e9a' }}>{`Send automated texts to leads · $${getSMSPrice()}/yr`}</p>
          </div>
        </div>

        {/* Active state */}
        {enabled ? (
          <div style={{ padding:'12px 16px 14px', borderTop:'1px solid rgba(0,0,0,0.05)' }}>
            <p style={{ fontSize:'11px', color:'#8a9e9a', fontWeight:600, textTransform:'uppercase', letterSpacing:'0.4px', marginBottom:'6px' }}>From Number</p>
            <div style={{ display:'flex', gap:'8px' }}>
              <input placeholder='Assigned on activation' style={{ flex:1, padding:'9px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'16px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', background:'rgba(0,0,0,0.02)' }} readOnly />
              <button style={{ padding:'9px 14px', background:'#1a2e2b', border:'none', borderRadius:'8px', fontSize:'12px', fontFamily:'inherit', color:'white', cursor:'pointer', fontWeight:500 }}>Manage</button>
            </div>
            <p style={{ fontSize:'11px', color:'#8a9e9a', marginTop:'8px' }}>{`Renews March 1, 2027 · $${getSMSPrice()}/yr`}</p>
          </div>
        ) : (
          <div style={{ padding:'12px 16px 14px', borderTop:'1px solid rgba(0,0,0,0.05)', background:'rgba(0,0,0,0.01)' }}>
            <div style={{ display:'flex', gap:'12px', alignItems:'center', marginBottom:'10px' }}>
              {[[`$${getSMSPrice()}/yr`,'Annual rate'],['$'+proration.prorated,'Due today'],['Mar 1, 2027','Renews']].map(([v,l])=>(
                <div key={l} style={{ flex:1, textAlign:'center', padding:'8px', background:'white', borderRadius:'8px', border:'1px solid rgba(0,0,0,0.06)' }}>
                  <p style={{ fontSize:'14px', fontWeight:700, color:'#1a2e2b', fontFamily:'Georgia,serif' }}>{v.includes('$')?v:`$${v}`}</p>
                  <p style={{ fontSize:'10px', color:'#8a9e9a' }}>{l}</p>
                </div>
              ))}
            </div>
            <p style={{ fontSize:'11px', color:'#8a9e9a', marginBottom:'10px', lineHeight:1.4 }}>SMS steps in paths and templates are locked until activated. Prorated to your March 1 renewal.</p>
            <button onClick={()=>setShowPayModal(true)} style={{ width:'100%', padding:'11px', background:'#1a2e2b', border:'none', borderRadius:'9px', fontSize:'13px', fontFamily:'inherit', fontWeight:600, color:'white', cursor:'pointer' }}>
              Activate SMS · ${proration.prorated} today →
            </button>
          </div>
        )}
      </div>

      {showPayModal&&(
        <SubscriptionPaymentModal
          plan="SMS Messaging"
          amount={proration.prorated}
          annual={getSMSPrice()}
          renewDate={proration.renewDate}
          isProrated={true}
          onClose={()=>setShowPayModal(false)}
          onPaid={()=>{ updateLocation('smsEnabled',true); setShowPayModal(false) }}
        />
      )}
    </>
  )
}

